mapper.update:
UPDATE coupon_issue
SET status = #{status}
WHERE issueNo = #{issueNo}

mapper.select:
SELECT DISTINCT ci.issueNo, ci.couponNo, ci.memberUid, ci.status, ci.createdAt, c.name AS couponName, c.couponType, c.benefit, c.sellerUid FROM coupon_issue ci JOIN coupon c ON ci.couponNo = c.couponNo LEFT JOIN seller s ON c.sellerUid = s.uid WHERE ci.memberUid = #{memberUid} AND ci.status = 0 AND (c.expireDate IS NULL OR c.expireDate >= CURDATE()) AND (c.sellerUid IS NULL OR s.status != 'SUSPENDED') AND ( c.sellerUid IS NULL OR c.sellerUid IN
#{sellerUid}
) ORDER BY ci.createdAt DESC
